{
    "$schema": "http://json-schema.org/draft-04/schema",
    "id": "https://raw.githubusercontent.com/Microsoft/azure-pipelines-task-lib/master/tasks.schema.json",
    "title": "Azure DevOps Tasks schema",
    "type": "object",
    "additionalProperties": false,
    "properties": {
        "id": {
            "type": "string",
            "description": "A unique guid for this task",
            "pattern": "^[A-Fa-f0-9]{8}-[A-Fa-f0-9]{4}-[A-Fa-f0-9]{4}-[A-Fa-f0-9]{4}-[A-Fa-f0-9]{12}$"
        },
        "name": {
            "type": "string",
            "description": "Name with no spaces",
            "pattern": "^[A-Za-z0-9\\-]+$"
        },
        "friendlyName": {
            "type": "string",
            "description": "Descriptive name (spaces allowed). Must be <= 40 chars"
        },
        "description": {
            "type": "string",
            "description": "Detailed description of what your task does"
        },
        "helpUrl": {
            "type": "string"
        },
        "helpMarkDown": {
            "type": "string"
        },
        "author": {
            "type": "string"
        },
        "preview": {
            "type": "boolean"
        },
        "deprecated": {
            "type": "boolean",
            "description": "Task is deprecated only when the latest version is marked as deprecated. Deprecated tasks appear at the end of searches under a section that is collapsed by default."
        },
        "showEnvironmentVariables": {
            "type": "boolean",
            "description": "Toggles showing the environment variable editor in the task editor UI. Allows passing environment variables to script based tasks."
        },
        "runsOn": {
            "type": "array",
            "items": {
                "type": "string",
                "enum": [
                    "Agent",
                    "MachineGroup",
                    "Server"
                ]
            }
        },
        "visibility": {
            "type": "array",
            "items": {
                "type": "string",
                "enum": [
                    "Build",
                    "Release"
                ]
            }
        },
        "category": {
            "type": "string",
            "description": "Where the task appears in Azure DevOps. Use the 'Azure *' categories for Azure DevOps and Azure DevOps Server 2019. Use the other categories for Team Foundation Server 2018 and below.",
            "enum": [
                "Build",
                "Utility",
                "Test",
                "Package",
                "Deploy",
                "Azure Repos",
                "Azure Boards",
                "Azure Pipelines",
                "Azure Test Plans",
                "Azure Artifacts"
            ]
        },
        "groups": {
            "type": "array",
            "description": "Describes groups that task properties may be logically grouped by in the UI.",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "required": [
                    "name",
                    "displayName"
                ],
                "properties": {
                    "name": {
                        "type": "string"
                    },
                    "displayName": {
                        "type": "string"
                    },
                    "isExpanded": {
                        "type": "boolean"
                    },
                    "visibleRule": {
                        "type": "string",
                        "description": "Allow's you to define a rule which dictates when the group will be visible to a user, for example \"variableName = value\""
                    }
                }
            }
        },
        "demands": {
            "type": "array",
            "description": "Allows you to define a list of demands that a build agent requires to run this build task.",
            "items": {
                "type": "string"
            }
        },
        "minimumAgentVersion": {
            "type": "string",
            "pattern": "^\\d+\\.\\d+(\\.\\d+)?$"
        },
        "version": {
            "type": "object",
            "additionalProperties": false,
            "description": "Always update this when you release your task, so that the agents utilize the latest code.",
            "required": [
                "Major",
                "Minor",
                "Patch"
            ],
            "properties": {
                "Major": {
                    "type": "number"
                },
                "Minor": {
                    "type": "number"
                },
                "Patch": {
                    "type": "number"
                }
            }
        },
        "instanceNameFormat": {
            "type": "string",
            "description": "This is how the task will be displayed within the build step list - you can use variable values by using $(variablename)"
        },
        "inputs": {
            "type": "array",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "required": [
                    "name",
                    "label",
                    "type"
                ],
                "properties": {
                    "name": {
                        "type": "string",
                        "description": "The variable name to use to store the user-supplied value",
                        "pattern": "^[A-Za-z][A-Za-z0-9]*$"
                    },
                    "label": {
                        "type": "string",
                        "description": "The text displayed to the user for the input label"
                    },
                    "type": {
                        "type": "string",
                        "description": "The type that dictates the control rendered to the user.",
                        "anyOf": [
                            {
                                "enum": [
                                    "boolean",
                                    "filePath",
                                    "multiLine",
                                    "pickList",
                                    "radio",
                                    "secureFile",
                                    "string"
                                ]
                            },
                            {
                                "type": "string",
                                "pattern": "^connectedService\\:.+$"
                            }
                        ]
                    },
                    "defaultValue": {
                        "type": [
                            "string",
                            "boolean"
                        ],
                        "description": "The default value to apply to this input."
                    },
                    "required": {
                        "type": "boolean",
                        "description": "Whether the input is a required field (default is false).",
                        "default": false
                    },
                    "helpMarkDown": {
                        "type": "string",
                        "description": "Help to be displayed when hovering over the help icon for the input. To display URLs use the format [Text To Display](http://Url)"
                    },
                    "groupName": {
                        "type": "string",
                        "description": "Setting this to the name of a group defined in 'groups' will place the input into that group."
                    },
                    "visibleRule": {
                        "type": "string",
                        "description": "Allow's you to define a rule which dictates when the input will be visible to a user, for example \"variableName = value\""
                    },
                    "properties": {
                        "type": "object",
                        "properties": {
                            "EditableOptions": {
                                "type": "string",
                                "enum": [
                                    "True",
                                    "False"
                                ]
                            }
                        }
                    },
                    "options": {
                        "type": "object",
                        "additionalProperties": true
                    }
                }
            }
        },
        "dataSourceBindings": {
            "type": "array",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                    "target": {
                        "type": "string"
                    },
                    "endpointId": {
                        "type": "string"
                    },
                    "dataSourceName": {
                        "type": "string"
                    },
                    "parameters": {
                        "type": "object"
                    },
                    "resultTemplate": {
                        "type": "string"
                    },
                    "endpointUrl": {
                        "type": "string"
                    },
                    "resultSelector": {
                        "type": "string"
                    }
                }
            }
        },
        "sourceDefinitions": {
            "type": "array",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "properties": {
                    "target": {
                        "type": "string"
                    },
                    "endpoint": {
                        "type": "string"
                    },
                    "selector": {
                        "type": "string"
                    },
                    "keySelector": {
                        "type": "string"
                    },
                    "authKey": {
                        "type": "string"
                    }
                }
            }
        },
        "prejobexecution": {
            "type": "object",
            "additionalProperties": false,
            "description": "Execution options for this task (on Pre-Job stage)",
            "properties": {
                "Node10": {
                    "$ref": "#/definitions/executionObject"
                },
                "Node": {
                    "$ref": "#/definitions/executionObject"
                },
                "PowerShell3": {
                    "$ref": "#/definitions/executionObject"
                },
                "PowerShell": {
                    "$ref": "#/definitions/executionObject"
                }
            }
        },
        "execution": {
            "type": "object",
            "additionalProperties": false,
            "description": "Execution options for this task",
            "properties": {
                "Node10": {
                    "$ref": "#/definitions/executionObject"
                },
                "Node": {
                    "$ref": "#/definitions/executionObject"
                },
                "PowerShell3": {
                    "$ref": "#/definitions/executionObject"
                },
                "PowerShell": {
                    "$ref": "#/definitions/executionObject"
                }
            }
        },
        "postjobexecution": {
            "type": "object",
            "additionalProperties": false,
            "description": "Execution options for this task (on Post-Job stage)",
            "properties": {
                "Node10": {
                    "$ref": "#/definitions/executionObject"
                },
                "Node": {
                    "$ref": "#/definitions/executionObject"
                },
                "PowerShell3": {
                    "$ref": "#/definitions/executionObject"
                },
                "PowerShell": {
                    "$ref": "#/definitions/executionObject"
                }
            }
        },
        "messages": {
            "type": "object"
        },
        "OutputVariables": {
            "type": "array",
            "description": "Describes output variables of task.",
            "items": {
                "type": "object",
                "additionalProperties": false,
                "required": [
                    "name"
                ],
                "properties": {
                    "name": {
                        "type": "string",
                        "description": "The variable name",
                        "pattern": "^[A-Za-z][A-Za-z0-9]*$"
                    },
                    "description": {
                        "type": "string",
                        "description": "Detailed description of the variable"
                    }
                }
            }
        },
        "$schema": {
            "type": "string"
        }
    },
    "definitions": {
        "executionObject": {
            "type": "object",
            "additionalProperties": true,
            "properties": {
                "target": {
                    "type": "string",
                    "description": "The target file to be executed. You can use variables here in brackets e.g. $(currentDirectory)\filename.ps1"
                },
                "platforms": {
                    "type": "array",
                    "items": {
                        "enum": [
                            "windows"
                        ]
                    }
                }
            }
        }
    }
}

{
    "id": "https://almanak.github.io/schemas/events.aarhusteater.json",
    "$schema": "http://json-schema.org/draft-04/schema#",
    "title": "events.aarhusteater",
    "description": "Schema for all plays at Aarhus Teater. Must extend the generic people-schema.",
    "type": "object",
    "_meta": {
        "indexProperties": [
            "id",
            "domain",
            "schema",
            "from_date",
            "to_date"
        ],
        "systemProperties": [
            "uuid",
            "id",
            "domain",
            "schema",
            "scheme",
            "created",
            "created_by",
            "updated",
            "updated_by",
            "ext_data.scope",
            "status"
        ],
        "fulltextProperties": [
            "description"
        ],
        "autocompleteProperties": [
            "display_label"
        ]
    },
    "properties": {
        "uuid": {
            "type": "string",
            "title": "Universal unique identifier",
            "description": "UUID1. Assigned by system",
            "pattern": "[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}"
        },
        "id": {
            "type": "string",
            "title": "Resourcespecifik ID",
            "description": "9-cifret l\u00f8benummer semi-specifik for resourcetypen. Assigned by system",
            "pattern": "^[0-9]+$"
        },
        "domain": {
            "type": "string",
            "enum": [
                "records",
                "people",
                "organisations",
                "families",
                "events",
                "places",
                "concepts",
                "things"
            ],
            "title": "Resourcetype",
            "description": "S\u00e6ttes kun n\u00e5r der v\u00e6lges skema til oprettelse. Ellers fastsat."
        },
        "schema": {
            "type": "string",
            "title": "Skema",
            "description": "S\u00e6ttes kun n\u00e5r der v\u00e6lges skema til oprettelse. Ellers fastsat."
        },
        "created": {
            "type": "string",
            "format": "date-time",
            "title": "Skabt",
            "description": "Datetime for skabelse af metadata-ressourcen"
        },
        "created_by": {
            "type": "string",
            "maxLength": 255,
            "title": "Skabt af",
            "description": "Brugernavn/ID p\u00e5 skaber/oploader af metadata-ressourcen"
        },
        "updated": {
            "type": "string",
            "format": "date-time",
            "title": "Senest opdateret",
            "description": "Datetime for seneste opdatering af ressourcen"
        },
        "updated_by": {
            "type": "string",
            "maxLength": 255,
            "title": "Senest opdateret af",
            "description": "Brugernavn p\u00e5 seneste opdaterer af metadata-ressourcen"
        },
        "status": {
            "type": "string",
            "enum": [
                "validated",
                "machine-generated",
                "user-generated"
            ],
            "title": "Status",
            "default": "user-generated"
        },
        "name": {
            "type": "string",
            "maxLength": 255,
            "title": "Forestillingsnavn",
            "description": "Navnet p\u00e5 forestillingen (uden \u00e5rstal)"
        },
        "display_label": {
            "type": "string",
            "maxLength": 255,
            "title": "Displaynavn",
            "description": "Den label, som entiteten repr\u00e6senteres med"
        },
        "description": {
            "type": "string",
            "maxLength": 5000,
            "title": "Beskrivelse"
        },
        "sources": {
            "type": "string",
            "title": "Kilder",
            "description": "URL-links eller enkeltlinje referencer"
        },
        "portrait": {
            "type": "string",
            "maxLength": 255,
            "format": "uri",
            "title": "Portr\u00e6t"
        },
        "date_from": {
            "type": "string",
            "format": "date",
            "title": "F\u00f8dselsdato (\u00e5\u00e5\u00e5\u00e5-mm-dd)",
            "pattern": "^([0-9]{4})(-([0-9]{2}))?(-([0-9]{2}))?$"
        },
        "date_to": {
            "type": "string",
            "format": "date",
            "title": "D\u00f8dsdato (\u00e5\u00e5\u00e5\u00e5-mm-dd)",
            "pattern": "^([0-9]{4})(-([0-9]{2}))?(-([0-9]{2}))?$"
        },
        "ext_data": {
            "type": "object",
            "title": "Udvided metadata",
            "properties": {
                "original_id": {
                    "type": "string",
                    "title": "Originalt ID"
                },
                "poster": {
                    "type": "boolean",
                    "title": "Plakat"
                },
                "stagename": {
                    "type": "string",
                    "title": "Scene"
                },
                "composer": {
                    "type": "string",
                    "title": "Komponist"
                },
                "translater": {
                    "type": "string",
                    "title": "Overs\u00e6tter"
                },
                "publisher": {
                    "type": "string",
                    "title": "Udgiver"
                },
                "programme": {
                    "type": "boolean",
                    "title": "Program"
                },
                "season": {
                    "type": "string",
                    "title": "S\u00e6son"
                },
                "playwright": {
                    "type": "string",
                    "title": "Forfatter"
                },
                "director": {
                    "type": "string",
                    "title": "Instrukt\u00f8r"
                },
                "scenographer": {
                    "type": "string",
                    "title": "Scenograf"
                }
            }
        }
    }
}

