            "date_to"
        ],
        "systemProperties": [
            "uuid",
            "id",
            "domain",
            "schema",
            "scheme",
            "created",
            "created_by",
            "updated",
            "updated_by",
            "status"
        ],
        "fulltextProperties": [
            "description"
        ],
        "autocompleteProperties": [
            "display_label"
        ]
    },
    "required": [
        "lastnames",
        "gender"
    ],
    "properties": {
        "uuid": {
            "type": "string",
