        },
        "description": {
            "type": "string",
            "maxLength": 5000,
            "title": "Beskrivelse"
        },
        "sources": {
            "type": "array",
            "items": {
                "type": "string",
                "maxLength": 255
            },
            "title": "Kilder",
            "description": "URL-links eller enkeltlinje referencer"
        },
        "portrait": {
            "type": "string",
            "maxLength": 255,
            "format": "uri",
            "title": "Portr\u00e6t"
        },
        "firstnames": {
