                    "type": "string",
                    "maxLength": 255,
                    "title": "Uddannelsessted"
                },
                "year_of_graduation": {
                    "type": "string",
                    "pattern": "^[0-9]{4}$",
                    "title": "Uddannelses\u00e5r"
                }
            }
        }
    }
}
